-- resume-specific settings
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Resume', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'Professional credentials and experience', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use the credential title followed by organization and dates. Be specific — this is the headline that appears in the profile view."},"content":{"tips":"Write for recruiters and hiring managers scanning quickly. Lead with impact and achievements. Quantify results wherever possible."},"formatting":["Bullet lists: key achievements and responsibilities","Bold: job titles, organization names, and key metrics","Tables: skills proficiency, technology stack","Numbered lists: ranked accomplishments or sequential milestones","Links: project URLs, publication DOIs, credential verification"],"avoid":["Vague responsibility descriptions without outcomes","Unexplained employment gaps (address them proactively)","Listing every technology without indicating proficiency level","Dense paragraphs instead of scannable bullet points"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":200},"content":{"min":20,"max":10000},"sourceAi":{"min":1,"max":100}}', datetime('now'));

-- Site actions (resume)
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('062ac933-b6d9-447d-8b69-cb691c3acd06', 'Contact', 'contact', 'Get in touch about opportunities', '[{"name":"name","type":"text","label":"Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"message","type":"textarea","label":"Message","required":true,"placeholder":"Tell me about the opportunity or how I can help...","maxLength":2000}]', '{"success_message":"Thanks for reaching out! I''ll review your message and respond soon.","require_honeypot":true}', 'active', '2026-03-27T01:22:55.618Z', '2026-03-27T01:22:55.618Z');
